long long solve(vector<long long> nums, long long p, vector<vector<long long>> queries) {
    // Note: The input signature uses Array<Int64>, which maps to vector<long long> in C++.

    Solver solver(nums, p);
    long long count = 0;

    for (const auto& query : queries) {
        int index = (int)query[0];
        long long val = query[1];

        // 1. Update the array state
        solver.update(index, val);

        // 2. Check for good subsequence
        if (solver.check_good_subsequence()) {
            count++;
        }
    }

    return count;
}
