ll solve(vector<ll> nums, ll p, vector<vector<ll>> queries) {
    int n = nums.size();
    ll good_subsequence_count = 0;

    for (const auto& query : queries) {
        int ind = (int)query[0];
        ll val = query[1];

        // Update nums array
        ll old_val = nums[ind];
        nums[ind] = val;

        // Rebuild the list of multiples of p from scratch (O(N))
        vector<ll> multiples_of_p;
        for (ll x : nums) {
            if (x % p == 0) {
