            }
        }

        // Check for good subsequence (O(N))
        bool exists = false;

        if (!multiples_of_p.empty()) {
            ll current_gcd = multiples_of_p[0];
            for (size_t i = 1; i < multiples_of_p.size(); ++i) {
                current_gcd = gcd(current_gcd, multiples_of_p[i]);
            }

            if (current_gcd == p) {
                int C = multiples_of_p.size();
                if (C < n) {
                    exists = true; // Case 1: Set of all multiples is good.
                } else { // C == n (all elements are multiples of p)
